    if (force_safe_idle) {
        controller_force_safe_idle(controller);
    } else if (controller_any_sensor_stale(controller, input.now_ms)) {
        controller_force_safe_idle(controller);
        output.timed_out = true;
    } else if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
    } else {
        const int turbidity = controller->last_turbidity_ntu;
        const int level = controller->last_level;
        const bool cloudy = turbidity > CONTROLLER_CLEAR_THRESHOLD_NTU;
        const bool very_cloudy = turbidity > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU;
        const bool disturbance = turbidity > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU;

        if (level < CONTROLLER_COMPLETE_LEVEL) {
            controller->clear_streak_count = 0;
            controller->settling_started_ms = 0U;
            controller_set_complete(controller);
        } else if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
            if ((level >= CONTROLLER_MIN_PROCESS_LEVEL) && cloudy) {
                controller->clear_streak_count = 0;
                controller_set_filtering(controller);
            } else {
                controller_set_safe_idle(controller);
            }
        } else if (controller->state == CONTROLLER_STATE_FILTERING) {
            if (cloudy) {
                controller_set_filtering(controller);
            } else if ((level >= CONTROLLER_MIN_PROCESS_LEVEL) &&
                       (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED)) {
                controller->settling_started_ms = input.now_ms;
                controller_set_settling(controller);
            } else {
                controller_set_filtering(controller);
            }
        } else if (controller->state == CONTROLLER_STATE_SETTLING) {
            if (very_cloudy) {
                controller->clear_streak_count = 0;
                controller_set_filtering(controller);
            } else if (((uint32_t) (input.now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS) &&
                       !cloudy &&
                       (level >= CONTROLLER_MIN_PROCESS_LEVEL)) {
                controller_set_draining(controller);
            } else {
                controller_set_settling(controller);
            }
        } else if (controller->state == CONTROLLER_STATE_DRAINING) {
            if (disturbance && (level >= CONTROLLER_MIN_PROCESS_LEVEL)) {
                controller->clear_streak_count = 0;
                controller_set_filtering(controller);
            } else {
                controller_set_draining(controller);
            }
        } else if (controller->state == CONTROLLER_STATE_COMPLETE) {
            if ((level >= CONTROLLER_MIN_PROCESS_LEVEL) && cloudy) {
                controller->clear_streak_count = 0;
                controller_set_filtering(controller);
            } else {
                controller_set_complete(controller);
            }
        } else {
            controller_set_safe_idle(controller);
        }
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

